mapper.select:
SELECT /* @SQLID=SUB0403-01#Sql003 */ K.* ,L.USER_NM AS CHARGE_NAME FROM ( SELECT C.CODE_NAME AS DOC_NAME_FILE_NAME ,D.CODE_NAME AS PROCESS_CONTENT ,A.COR_USER_ID AS LOGIN_ID ,TO_CHAR ( COR_TS, 'YYYY/MM/DD HH24:MI:SS') AS PROCESS_DAY_TIME ,DECODE(A.COR_NAME_FLG,'1','Ｏ','') NAME ,DECODE(A.COR_ADDRESS_FLG,'1','Ｏ','') ADRESS ,DECODE(A.COR_TELNO_FLG,'1','Ｏ','') TEL ,DECODE(A.COR_OFFICE_FLG,'1','Ｏ','') OFFICE ,DECODE(A.COR_BIRTH_FLG,'1','Ｏ','') COR_BIRTH_FLG ,DECODE(A.COR_SEX_FLG,'1','Ｏ','') GENDER ,DECODE(A.COR_EMPLOYMENT_FLG,'1','Ｏ','') ASSETS ,DECODE(A.COR_OCCUPATION_FLG,'1','Ｏ','') PROFESSION ,DECODE(A.COR_BUTEN_ACCOUNT_FLG,'1','Ｏ','') BUTEN_ACCOUNT ,DECODE(A.COR_EMAIL_FLG,'1','Ｏ','') EMAIL ,DECODE(A.COR_DRAWERSACCOUNT_FLG,'1','Ｏ','') WITHDRAW_ACCOUNT ,A.COR_DATA_COUNT AS ACQUIRE_DATA_CUSTOMER_COUNT ,TRIM(A.COR_TRANSFER_CODE) AS STORAGE_SENDING_MEDIUM ,TRIM(A.COR_DEPOSIT) AS DEPOSIT_DESTINATIONS ,TRIM(A.COR_DONATION) AS DESTINATION ,TRIM(A.COR_DEPOSITORY) AS STORAGE_SPACE ,A.COR_DEPOSITORY_TERM AS PRESERVE_PERIOD ,TRIM(A.COR_DIPOSAL_METHOD) AS DISPOSE_METHOD ,TRIM(A.COR_DIPOSAL_FLG) AS NOT_DISPOSE ,TRIM(A.COR_DIPOSAL_DATE) AS DISPOSE_DATE_YMD ,A.COR_DEPOSIT_OUTLINE AS COR_DEPOSIT_OUTLINE ,A.COR_DONATION_OUTLINE AS COR_DONATION_OUTLINE ,A.COR_DEPOSITORY_OUTLINE AS COR_DEPOSITORY_OUTLINE ,A.COR_ID AS PERSONAL_INFO_MANAGE_ID ,A.INITIAL_GET_INFO_USER_NAME AS PERSONAL_INFO_ACQUIRE FROM COR_USER_ATTRBUTE_INFO A LEFT JOIN ( SELECT * FROM CORDYS_CODE_MASTER WHERE FUNCTION_ID = '015' ) C ON TRIM(A.COR_DOCUMENT) = C.CODE_ID LEFT JOIN ( SELECT * FROM CORDYS_CODE_MASTER WHERE FUNCTION_ID = '016' ) D ON TRIM(A.COR_TRANSACTION_DESC) = D.CODE_ID
TO_DATE(TO_CHAR (A.COR_TS, 'yyyy-mm-dd'), 'yyyy-mm-dd') >= TO_DATE(#{req.processTargetPeriodFrom}, 'yyyy-mm-dd')
AND TO_DATE(TO_CHAR (A.COR_TS, 'yyyy-mm-dd'), 'yyyy-mm-dd') <= TO_DATE(#{req.processTargetPeriodTo}, 'yyyy-mm-dd')
AND (A.BROKER_CODE IN
) OR A.BROKER_CODE IN(
,
#{brokerCharge.brokerCode}
)
) K LEFT JOIN TB_MED_USERS L ON K.LOGIN_ID = L.USER_ID WHERE ROWNUM <= #{req.maxRow} ORDER BY K.PROCESS_DAY_TIME DESC

SELECT /* @SQLID=SUB0403-01#Sql005 */ COUNT(1) as row_count FROM ( SELECT K.COR_ID FROM ( SELECT A.COR_ID ,C.CODE_NAME AS COR_DOCUMENT ,D.CODE_NAME AS COR_TRANSACTION_DESC ,A.COR_USER_ID ,COR_TS ,A.COR_NAME_FLG ,A.COR_ADDRESS_FLG ,A.COR_TELNO_FLG ,A.COR_OFFICE_FLG ,A.COR_BIRTH_FLG ,A.COR_SEX_FLG ,A.COR_EMPLOYMENT_FLG ,A.COR_OCCUPATION_FLG ,A.COR_BUTEN_ACCOUNT_FLG ,A.COR_EMAIL_FLG ,A.COR_DRAWERSACCOUNT_FLG ,A.COR_DATA_COUNT ,A.COR_TRANSFER_CODE ,A.COR_DEPOSIT ,A.COR_DONATION ,A.COR_DEPOSITORY ,A.COR_DEPOSITORY_TERM ,A.COR_DIPOSAL_METHOD ,A.COR_DIPOSAL_FLG ,A.COR_DIPOSAL_DATE ,A.COR_DEPOSIT_OUTLINE ,A.COR_DONATION_OUTLINE ,A.COR_DEPOSITORY_OUTLINE FROM COR_USER_ATTRBUTE_INFO A LEFT JOIN ( SELECT * FROM CORDYS_CODE_MASTER WHERE FUNCTION_ID = '015' ) C ON TRIM(A.COR_DOCUMENT) = C.CODE_ID LEFT JOIN ( SELECT * FROM CORDYS_CODE_MASTER WHERE FUNCTION_ID = '016' ) D ON TRIM(A.COR_TRANSACTION_DESC) = D.CODE_ID
TO_DATE(TO_CHAR (A.COR_TS, 'yyyy-mm-dd'), 'yyyy-mm-dd') >= TO_DATE(#{req.processTargetPeriodFrom}, 'yyyy-mm-dd')
AND TO_DATE(TO_CHAR (A.COR_TS, 'yyyy-mm-dd'), 'yyyy-mm-dd') <= TO_DATE(#{req.processTargetPeriodTo}, 'yyyy-mm-dd')
AND (A.BROKER_CODE IN
) OR A.BROKER_CODE IN(
,
#{brokerCharge.brokerCode}
)
) K LEFT JOIN TB_MED_USERS L ON K.COR_USER_ID = L.USER_ID )
